def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """

    # reverse string
    rev = ''.join(reversed(s))

    # check for letter
    for i in s:
        if i.isalpha():
            # swap upper and lower cases
            if i.isupper():
                return rev.replace(i, i.lower())
            else:
                return rev.replace(i, i.upper())

    return rev

